import scala.collection.mutable

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  queries.map { case Array(li, ri, threshold) =>
    val subarray = nums.slice(li.toInt, ri.toInt + 1)
    val freq = mutable.HashMap.empty[Long, Int]
    subarray.foreach { num =>
      freq.put(num, freq.getOrElse(num, 0) + 1)
    }
    val candidates = freq.filter { case (_, count) => count >= threshold.toInt }.toList
    if (candidates.isEmpty) {
      -1L
    } else {
      candidates.minBy { case (num, count) => (-count, num) }._1
    }
  }
}
